import 'package:flutter/material.dart';

class TextStylesDemo extends StatelessWidget {
  const TextStylesDemo({super.key});

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Scaffold(
      appBar: AppBar(title: const Text('Text Styles')),
      body: Padding(
        padding: const EdgeInsets.all(16),
        child: Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text('Headline Large', style: theme.textTheme.headlineLarge),
            const SizedBox(height: 4),
            Text('Title Medium', style: theme.textTheme.titleMedium),
            const SizedBox(height: 4),
            Text('Body Large', style: theme.textTheme.bodyLarge),
            const SizedBox(height: 16),
            const Text('Custom styled', style: TextStyle(
              fontSize: 20,
              color: Colors.purple,
              fontWeight: FontWeight.w300,
              letterSpacing: 2,
              decoration: TextDecoration.underline,
            )),
            const SizedBox(height: 16),
            RichText(
              text: const TextSpan(
                style: TextStyle(fontSize: 16, color: Colors.black),
                children: [
                  TextSpan(text: 'Mixed ', style: TextStyle(color: Colors.red)),
                  TextSpan(text: 'text ', style: TextStyle(fontWeight: FontWeight.bold)),
                  TextSpan(text: 'styles', style: TextStyle(fontStyle: FontStyle.italic)),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }
}
